const ctx = $('Normaliseer Laravel payload').item.json;
const res = $json;

function apiErrorMessage(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (typeof payload.error === 'string') return payload.error;
  if (payload.error && typeof payload.error === 'object') {
    return payload.error.message || payload.error.description || null;
  }
  if (typeof payload.message === 'string') return payload.message;
  return null;
}

if (!ctx.sql_token) {
  return [{ json: {
    answer: 'Live tarieven vereisen een sql_token vanuit Laravel. Test via de website-chat of stuur de volledige Laravel webhook payload mee.',
    source: 'blocked',
    hint: 'payload_source=' + (ctx.payload_source || 'unknown')
  }}];
}

const apiError = apiErrorMessage(res);
if (apiError && /timeout|ECONNABORTED|ETIMEDOUT/i.test(apiError)) {
  return [{ json: {
    answer: 'Laravel live-query API reageerde niet op tijd. Lokaal: herstart Docker backend met PHP_CLI_SERVER_WORKERS=8 en `php artisan serve --no-reload`. Controleer ngrok en AI_CHAT_LARAVEL_API_URL.',
    source: 'blocked',
    error: apiError
  }}];
}

if (res.success === false || res.error) {
  return [{ json: { answer: apiError || res.error || res.message || 'Kon geen databasegegevens ophalen.', source: 'blocked' } }];
}

if (typeof res === 'string' && res.trim().startsWith('<!DOCTYPE')) {
  return [{ json: {
    answer: 'Laravel API niet bereikbaar of niet gedeployed. Controleer GET https://nexasuite.nl/integrations/n8n/ai-chat/live-query/health',
    source: 'blocked'
  }}];
}

if (res.source === 'public_rates' && typeof res.answer === 'string' && res.answer.trim() !== '') {
  return [{ json: { answer: res.answer.trim(), source: 'public_rates' } }];
}

const rows = Array.isArray(res.rows) ? res.rows : [];
if (!rows.length) {
  return [{ json: { answer: 'Geen resultaten gevonden in de Nexa Taxi database.', source: res.source || 'sql', count: 0 } }];
}

const mapped = rows.map((r) => ({
  id: String(r.id ?? ''),
  klant_naam: r.customer_name ?? r.klant_naam ?? 'Rit',
  pickup_adres: r.pickup_address ?? r.pickup_adres ?? '',
  dropoff_adres: r.dropoff_address ?? r.dropoff_adres ?? '',
  pickup_tijd: r.pickup_at ?? r.pickup_tijd ?? '',
  status: r.status ?? '',
}));

return [{ json: { answer: mapped, count: res.count ?? mapped.length, source: res.source || 'sql' } }];

return [{
  json: {
    answer: 'Daar kan ik je helaas geen informatie over geven. Stel je vraag gerust op een andere manier, of neem contact met ons op.',
    source: 'denied'
  }
}];
